import{c as e,Q as l,j as r,m as t}from"./chunks/framework.BPKcPtvA.js";const _=JSON.parse('{"title":"redo log（重做日志）","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/log/redolog.md","filePath":"mysql/log/redolog.md","lastUpdated":1779806814000}'),a={name:"mysql/log/redolog.md"};function d(n,o,i,g,s,c){return l(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="redo-log-重做日志" tabindex="-1">redo log（重做日志） <a class="header-anchor" href="#redo-log-重做日志" aria-label="Permalink to &quot;redo log（重做日志）&quot;">​</a></h1><blockquote><p>InnoDB 的 crash-safe 机制核心——保证事务的持久性。</p></blockquote><hr><h2 id="🔑-为什么需要-redo-log" tabindex="-1">🔑 为什么需要 redo log？ <a class="header-anchor" href="#🔑-为什么需要-redo-log" aria-label="Permalink to &quot;🔑 为什么需要 redo log？&quot;">​</a></h2><p>MySQL 数据在磁盘，每次读写都走磁盘太慢。InnoDB 的做法：</p><ol><li>修改先写内存（Buffer Pool）</li><li>写 redo log（顺序写，很快）</li><li>后台异步刷脏页到磁盘</li></ol><p><strong>崩溃恢复时</strong>：通过 redo log 恢复未刷盘的数据。</p><hr><h2 id="📐-redo-log-结构" tabindex="-1">📐 redo log 结构 <a class="header-anchor" href="#📐-redo-log-结构" aria-label="Permalink to &quot;📐 redo log 结构&quot;">​</a></h2><ul><li><strong>循环写</strong>：固定大小，写满后触发 checkpoint</li><li><strong>WAL 技术</strong>：Write-Ahead Logging，先写日志再写磁盘</li><li><strong>刷盘策略</strong>：<code>innodb_flush_log_at_trx_commit</code></li></ul><hr><blockquote><p>📖 相关阅读：<a href="/mysql/log/how_update.html">undo log + redo log + bin log 协作</a></p></blockquote>',12)])])}const p=e(a,[["render",d]]);export{_ as __pageData,p as default};
